import { forwardRef, useRef, useImperativeHandle, useState, useEffect } from 'react'
import type { Project } from '../types'
import { iframeScript } from '../assets/assets';
import EditorPanel from './EditorPanel';

interface ProjectPreviewProps {
    project: Project;
    isGenerating: boolean;
    device?: 'phone' | 'tablet' | 'desktop';
    showEditorPanel?: boolean;
}

export interface ProjectPreviewRef {
    getCode: () => string | undefined
}

const ProjectPreview = forwardRef<ProjectPreviewRef, ProjectPreviewProps>(
    ({ project, isGenerating, device = 'desktop', showEditorPanel = true }, ref) => {

        const iframeRef = useRef<HTMLIFrameElement>(null)
        const [selectedElemnt, setSelectedElement] = useState<any>(null)

        const resolutions = {
            phone: 'w-[412px]',
            tablet: 'w-[786px]',
            desktop: 'w-full'
        }
        useImperativeHandle(ref, () => ({
            getCode: () => {
                const doc = iframeRef.current?.contentDocument;
                if (!doc) return undefined;

                // 1. Remove our selection class / attributes /outline from all elements
                doc.querySelectorAll('ai-selected-element,[data-ai-selected]').forEach
                    ((el) => {
                        el.classList.remove('ai-selected-element');
                        el.removeAttribute('data-ai-selected');
                        (el as HTMLElement).style.outline = '';
                    })

                // 2. Remove injected style + script from the decument 

                const previewStyle = doc.getElementById('ai-preview-style');
                if (previewStyle) previewStyle.remove();

                const previewScript = doc.getElementById('ai-preview-script')
                if (previewScript) previewScript.remove();

                // 3. Serialize clean Html

                const html = doc.documentElement.outerHTML;
                return html;
            }
        }))

        useEffect(() => {
            const handleMessage = (event: MessageEvent) => {
                if (event.data.type === 'ELEMENT_SELECTED') {
                    setSelectedElement(event.data.payload);
                } else if (event.data.type === '  clear_selection') {
                    setSelectedElement(null)
                }
            }
            window.addEventListener('message', handleMessage);
            return () => window.removeEventListener('message', handleMessage)
        }, [])


        const handleUpdate = (updates: any) => {
            if (iframeRef.current?.contentWindow) {
                iframeRef.current.contentWindow.postMessage({
                    type: 'UPDATE_ELEMENT',
                    payload: updates
                }, '*')
            }

        }

        const injectPreview = (html: string) => {
            if (!html) return '';
            if (!showEditorPanel) return html;

            if (html.includes('</body>')) {
                return html.replace('</body>', iframeScript + '</body>')
            } else {
                return html + iframeScript
            }
        }

        return (
            <div className='relative h-full bg-gray-900 flex-1 rounded-xl overflow-hidden max-sm:ml-2'>
                {project.current_code ? (
                    <>
                        <iframe
                            ref={iframeRef}
                            srcDoc={injectPreview(project.current_code)}
                            className={`h-full max-sm:w-full ${resolutions[device]} mx-auto transition-all`}
                        />
                        {showEditorPanel && selectedElemnt && (
                            <EditorPanel selectedElement={selectedElemnt}
                                onUpdate={handleUpdate} onClose={() => {
                                    setSelectedElement(null);
                                    if (iframeRef.current?.contentWindow) {
                                        iframeRef.current.contentWindow.postMessage({
                                            type:
                                                'CLEAR_SELECTION_REQUEST'
                                        }, '*')
                                    }
                                }} />
                        )}
                    </>
                ) : isGenerating && (
                    <div>loading</div>
                )}
            </div>
        )
    })

export default ProjectPreview

